// ============================================================================
// BUILD REQUEST - Prepare prompt for Gemini Veo-3
// ============================================================================

const input = $input.first().json;

// Extract prompt from various possible input fields
const promptText = input.prompt_text || input.prompt || input.query || input.description || 'A beautiful cinematic video';

// Clean the prompt - remove any problematic characters
const cleanPrompt = promptText
  .replace(/[\n\r]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 1000); // Limit prompt length

// Optional parameters
const duration = input.duration || 5;
const hasImage = !!(input.image_base64 || input.image_url);

return [{
  json: {
    clean_prompt: cleanPrompt,
    original_prompt: promptText,
    duration: duration,
    has_image: hasImage,
    promptImage: input.image_base64 || input.image_url || null,
    promptText: cleanPrompt
  }
}];

// ============================================================================
// EXTRACT VIDEO URL FROM FILE.IO RESPONSE
// ============================================================================

const response = $input.first().json;
const buildData = $('Build Request').item.json;

// file.io retourne: { success: true, key: "abc123", link: "https://file.io/abc123" }
const videoUrl = response.link || response.url || null;

if (!videoUrl) {
  // Log error details for debugging
  console.error('Upload response:', JSON.stringify(response));
  throw new Error('Video upload failed. Response: ' + JSON.stringify(response));
}

return [{
  json: {
    success: true,
    video_url: videoUrl,
    file_key: response.key || null,
    expires: response.expires || '1 day',
    script: buildData.original_prompt,
    clean_prompt: buildData.clean_prompt,
    mime_type: 'video/mp4'
  }
}];

// ============================================================================
// SUCCESS OUTPUT - Format final response for Creative V6
// ============================================================================

const videoData = $input.first().json;

return [{
  json: {
    success: true,
    tool: 'veo3_video_generator',
    video: {
      url: videoData.video_url,
      script: videoData.script,
      prompt_used: videoData.clean_prompt,
      expires: videoData.expires,
      file_key: videoData.file_key,
      mime_type: videoData.mime_type,
      downloadable: true
    },
    // Pour le frontend - UI Component
    ui_component: 'AD_PREVIEW',
    ui_data: {
      video_url: videoData.video_url,
      script: videoData.script,
      title: 'Video generee par Veo-3',
      downloadable: true
    },
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// ERROR HANDLER - Format error response
// ============================================================================

const error = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'veo3_video_generator',
    error: {
      message: error.message || 'Video generation failed',
      details: JSON.stringify(error)
    },
    video: null,
    generated_at: new Date().toISOString()
  }
}];
